import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { Mail, Phone, MapPin, Shield, ArrowRight } from 'lucide-react';
import type { Language } from '../constants/sections';
import { BrandingSeal, SectionBadge } from './Section';

interface ContactSectionProps {
  isActive: boolean;
  language: Language;
  backgroundImage?: string;
}

const contactData = {
  mk: {
    title: "Контакт",
    subtitle: "Подготвени сте за следното поглавје? Тука сме за вашите идеи и проекти.",
    button: "Испрати порака",
    info: { address: "Гостивар, Македонија", phone: "+389 70 123 456", email: "hello@mmmedia.mk" },
    copyright: "© 2016 M&M MEDIA"
  },
  en: {
    title: "Contact",
    subtitle: "Ready for the next chapter? We are here for your ideas and projects.",
    button: "Send Message",
    info: { address: "Gostivar, Macedonia", phone: "+389 70 123 456", email: "hello@mmmedia.mk" },
    copyright: "© 2016 M&M MEDIA"
  }
};

const ContactSection: React.FC<ContactSectionProps> = ({ isActive, language, backgroundImage }) => {
  const data = contactData[language];
  const sectionRef = useRef<HTMLElement>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  // Користи ја сликата од пропс, или фолбек ако не е дефинирана
  const bgImage = backgroundImage || 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&w=1920&q=80';

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"]
  });

  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    const img = new Image();
    img.src = bgImage;
    img.onload = () => setIsLoaded(true);
  }, [bgImage]);

  return (
    <section 
      id="contact" 
      ref={sectionRef}
      className="relative h-[100dvh] w-full snap-child flex flex-col justify-between overflow-hidden bg-surface"
    >
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          {isLoaded && (
            <motion.div 
              initial={{ opacity: 0, scale: 1.05 }}
              animate={isActive ? { opacity: 0.6, scale: 1 } : { opacity: 0, scale: 1.05 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.5, ease: [0.22, 1, 0.36, 1] }}
              className="absolute inset-0 z-0 bg-cover bg-center brightness-[0.7] contrast-[1.1]"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${bgImage})` 
              }}
            />
          )}
        </AnimatePresence>

        <div className="absolute inset-0 z-[3] pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-surface via-transparent to-surface" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-surface via-surface/40 to-transparent" />
          <div className="absolute inset-0 bg-black/10" />
        </div>
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 flex-1 flex flex-col justify-center max-w-7xl w-full mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={isActive ? { opacity: 1, y: 0 } : { opacity: 0, y: 30 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
        >
          <SectionBadge label="NETWORK_NODE_CONNECTED" />

          <h2 className="text-4xl md:text-5xl lg:text-7xl xl:text-8xl font-heading font-extrabold tracking-[-0.07em] mb-4 md:mb-8 text-white leading-[0.85] flex items-baseline">
            {data.title}<BrandingSeal />
          </h2>

          <p className="text-sm md:text-lg lg:text-xl text-white/60 max-w-2xl leading-[1.6] mb-6 md:mb-12 font-medium tracking-tight">
            {data.subtitle}
          </p>

          <motion.button 
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            className="group bg-primary text-white font-bold py-4 px-10 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-4 transition-all shadow-xl shadow-primary/20 w-fit"
          >
            <span className="text-[10px] md:text-[11px] uppercase tracking-[0.3em] font-black">{data.button}</span>
            <ArrowRight size={22} className="group-hover:translate-x-2 transition-transform" />
          </motion.button>
        </motion.div>
      </div>

      {/* Footer Info */}
      <div className="relative z-10 px-4 md:px-20 lg:px-32 pb-6 w-full max-w-7xl mx-auto">
        <div className="border-t border-white/10 pt-6">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
            <div className="flex flex-wrap gap-x-10 gap-y-4">
              <CompactInfo label="MAIL" value={data.info.email} icon={Mail} />
              <CompactInfo label="SIGNAL" value={data.info.phone} icon={Phone} />
              <CompactInfo label="GEO" value={data.info.address} icon={MapPin} />
            </div>

