import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { ArrowRight } from 'lucide-react';
import { SectionData } from '../constants/sections';

export const BrandingSeal = () => (
  <motion.span 
    animate={{ opacity: [0.6, 1, 0.6], scale: [1, 1.2, 1] }}
    transition={{ duration: 3, repeat: Infinity }}
    className="inline-block w-[0.16em] h-[0.16em] bg-primary rounded-full ml-[0.15em] mb-[0.05em] shadow-[0_0_15px_rgba(59,130,246,0.8)]" 
  />
);

export const SectionBadge = ({ label }: { label: string }) => (
  <div className="mb-6 md:mb-10">
    <span className="font-mono text-[10px] tracking-[0.3em] text-white/50 font-black uppercase">
      {label}
    </span>
  </div>
);

interface SectionProps extends SectionData {
  isActive: boolean;
}

const Section: React.FC<SectionProps> = ({ isActive, badge, title, content, showButton, buttonText, backgroundImage, id }) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);
  const { scrollYProgress } = useScroll({ target: sectionRef, offset: ["start end", "end start"] });
  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    const img = new Image();
    img.src = backgroundImage;
    img.onload = () => setIsLoaded(true);
  }, [backgroundImage]);

  return (
    <section ref={sectionRef} className="relative h-[100dvh] w-full snap-child flex flex-col justify-center overflow-hidden bg-surface">
      <div className="absolute inset-0 z-0">
        <AnimatePresence mode="wait">
          {isLoaded && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={isActive ? { opacity: 0.5 } : { opacity: 0 }}
              transition={{ duration: 1 }}
              className="absolute inset-0 bg-cover bg-center brightness-[0.6]"
              style={{ y: backgroundY, backgroundImage: `url(${backgroundImage})` }}
            />
          )}
        </AnimatePresence>
        <div className="absolute inset-0 bg-gradient-to-r from-surface via-surface/40 to-transparent z-[2]" />
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 max-w-7xl w-full mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isActive ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <SectionBadge label={badge} />
          <h1 className="text-4xl md:text-5xl lg:text-7xl xl:text-8xl font-heading font-extrabold tracking-tight mb-6 text-white leading-none">
            {title}<BrandingSeal />
          </h1>
          {content && <p className="text-sm md:text-lg lg:text-xl text-white/70 max-w-2xl mb-8 font-medium leading-relaxed">{content}</p>}
          {showButton && (
            <button className="bg-primary text-white font-bold py-4 px-10 rounded-xl flex items-center gap-4 hover:scale-105 transition-transform">
              <span className="text-[10px] uppercase tracking-widest font-black">{buttonText}</span>
              <ArrowRight size={20} />
            </button>
          )}
        </motion.div>
      </div>
    </section>
  );
};

export default Section;

